                                const fakeVulnName = this.fakeVulnName ??= turnLogic[ownerTurn.properName].buffNames.figmentVuln;
                                const buffCheck = sourceTurn.buffsObject[fakeVulnName];

                                if (buffCheck) {removeBuff(battleData,sourceTurn,buffCheck);}
