                        "source": characterName,
                        "sourceOwner": sourceTurn.properName,
                        "buffName": logicRef.buffNames.ultDebuff,
                        "durationInTurn": 4,
                        "duration": 3,
                        "AVApplied": 0,
                        "maxStacks": 1,
                        "currentStacks": 1,
                        "decay": false,
                        "isDebuff": true,
                        "expireType": "EndTurn",
